import './App.css';
import {useState} from 'react';
import Home from './Components/HomeScreen';
import TestScreen from './Components/TestScreen';

function App() {
  const [homeClear, setHomeClear] = useState(false);
  const [data, setData] = useState(null);
  const [questions, setQuestions] = useState(null);
  const [homeInfo, setHomeInfo] = useState(null);
  const [participantId, setParticipantId] = useState(null);
  const [configError, setConfigError] = useState(null);

  const handleParticipantSubmit = (id) => {
    setConfigError(null);
    fetch(`configs/${id}.json`)
      .then(response => {
        if (!response.ok) {
          throw new Error(`Config not found for participant "${id}"`);
        }
        return response.json();
      })
      .then(data => {
        setData(data);
        setQuestions(data.questions);
        setHomeInfo(data.homeInfo);
        setParticipantId(id);
      })
      .catch(error => {
        console.error(error);
        setConfigError(error.message);
      });
  };

  // Step 1: participant hasn't identified yet
  if (!data) {
    return (
      <div className="App flex items-center content-center justify-center pt-8">
        <Home
          setHomeClear={setHomeClear}
          homeInfo={null}
          onParticipantSubmit={handleParticipantSubmit}
          configError={configError}
        />
      </div>
    );
  }

  // Step 2: participant identified, show home info or test
  return (
    <div className="App flex items-center content-center justify-center pt-8">
      {homeClear
        ? <TestScreen questions={questions} participantId={participantId} />
        : <Home setHomeClear={setHomeClear} homeInfo={homeInfo} />
      }
    </div>
  );
}

export default App;
